import React from "react";
import "./Banner.css";

// Swiper imports
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";

function Banner() {
  return (
    <div className="banner">
      <Swiper spaceBetween={10} slidesPerView={1} autoplay={{ delay: 2000 }}>
       <SwiperSlide>
            <img src="https://via.placeholder.com/1600x270?text=Flipkart+Sale+1" />
        </SwiperSlide>

        <SwiperSlide>
            <img src="https://via.placeholder.com/1600x270?text=Big+Discount+Sale" />
        </SwiperSlide>

        <SwiperSlide>
            <img src="https://via.placeholder.com/1600x270?text=Best+Deals+Today" />
        </SwiperSlide>
      </Swiper>
    </div>
  );
}

export default Banner;
